const claudeBody = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 1024,
  system: systemPrompt,
  messages
});

return [{ json: { uuid, message, claudeBody, historyLength: history.length } }];

const rawText = Array.isArray($json.content)
  ? $json.content
      .filter(b => b.type === 'text')
      .map(b => b.text || '')
      .join('\n')
  : String($json.content || '');

const cotizarRegex = /\[COTIZAR:\s*([\s\S]*?)\]/i;
const pagarRegex = /\[PAGAR:\s*([\s\S]*?)\]/i;

const cotizarMatch = rawText.match(cotizarRegex);
const pagarMatch = rawText.match(pagarRegex);
console.log("muestra valor:", rawText.match(cotizarRegex));


function parseKeyValueBlock(blockText) {
  const result = {};
  const parts = blockText.split(/,\s*(?=[a-zA-Z_]+\s*=)/);

  for (const part of parts) {
    const idx = part.indexOf('=');
    if (idx === -1) continue;
    const key = part.slice(0, idx).trim().toLowerCase();
    const value = part.slice(idx + 1).trim();
    result[key] = value;
  }

  return result;
}

function limpiarNumero(str) {
  return parseInt(String(str || '').replace(/[$.\s]/g, '').replace(',', '.'), 10) || 0;
}

let cleanText = rawText
  .replace(cotizarRegex, '')
  .replace(pagarRegex, '')
  .trim();

let action = 'CHAT';
let actionData = null;

if (cotizarMatch) {
  const data = parseKeyValueBlock(cotizarMatch[1]);

  action = 'COTIZAR';
  actionData = {
    nombre: data.nombre || '',
    rut: data.rut || '',
    direccion: data.direccion || '',
    m2: parseFloat(data.m2 || '0') || 0,
    tipo: data.tipo || '',
    instalacion: String(data.instalacion || '').toUpperCase() === 'SI',
    total: limpiarNumero(data.total),
  };
} else if (pagarMatch) {
  const data = parseKeyValueBlock(pagarMatch[1]);

  action = 'PAGAR';
  actionData = {
    numero: data.numero || '',
    monto: limpiarNumero(data.monto),
  };
}

return [
  {
    json: {
      rawText,
      cleanText,
      action,
      actionData,
      debug: {
        cotizarFound: !!cotizarMatch,
        pagarFound: !!pagarMatch,
        cotizarBlock: cotizarMatch ? cotizarMatch[1] : null,
        pagarBlock: pagarMatch ? pagarMatch[1] : null,
      }
    }
  }
];

const parseData  = $('Parsear Respuesta Claude').first().json;
const actionData = parseData.actionData || {};
const uuid       = parseData.uuid || $('Extraer Input').first().json.uuid || 'sin-uuid';
const cleanText  = parseData.cleanText || '';

// Número de cotización: COT-AÑO-XXXXX (basado en timestamp)
